import{_ as e,o as t,c as i,ag as l}from"./chunks/framework.C9sp7nFj.js";const u=JSON.parse('{"title":"资源获取","description":"","frontmatter":{},"headers":[],"relativePath":"guide/help/resource-acquisition.md","filePath":"guide/help/resource-acquisition.md","lastUpdated":1780491682000}'),r={name:"guide/help/resource-acquisition.md"};function d(o,a,p,h,c,n){return t(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="资源获取" tabindex="-1">资源获取 <a class="header-anchor" href="#资源获取" aria-label="Permalink to &quot;资源获取&quot;">​</a></h1><p>资源获取是 PanSave 的主要工作区。它不是单个功能，而是一组互相配合的入口：先准备转存策略，再决定哪些频道、榜单或条目需要被搜索和跟踪。</p><h2 id="转存策略" tabindex="-1">转存策略 <a class="header-anchor" href="#转存策略" aria-label="Permalink to &quot;转存策略&quot;">​</a></h2><p>入口：<code>资源获取 / 转存策略</code></p><p>转存策略决定“资源存到哪里”。</p><p>你需要为网盘配置可用目录，并选择一个整理源目录。频道扫描、监控策略、豆瓣求片和 TMDB 看板即时转存都会使用整理源目录。</p><p>如果某个网盘没有整理源目录，它仍然能显示在配置里，但不会成为可用的自动转存目标。</p><h2 id="监控策略" tabindex="-1">监控策略 <a class="header-anchor" href="#监控策略" aria-label="Permalink to &quot;监控策略&quot;">​</a></h2><p>入口：<code>资源获取 / 监控策略</code></p><p>监控策略决定自动流程怎么跑：</p><ul><li>是否启用监控总开关</li><li>多久刷新一次</li><li>转存之间隔多久</li><li>使用哪些搜索来源</li><li>每个来源转存到哪个网盘</li><li>新条目是否一定先搜索</li></ul><p>如果你使用榜单订阅、TMDB 看板自定义监控、豆瓣求片或缺集补救，通常都需要先配置监控策略。</p><h2 id="频道扫描" tabindex="-1">频道扫描 <a class="header-anchor" href="#频道扫描" aria-label="Permalink to &quot;频道扫描&quot;">​</a></h2><p>入口：<code>资源获取 / 频道扫描</code></p><p>频道扫描适合处理频道历史消息。</p><p>推荐流程：</p><ol><li>选择要扫描的频道。</li><li>给频道关联一个网盘账号。</li><li>设置关键词、屏蔽词和单轮新增限制。</li><li>执行扫描。</li><li>查看扫描结果。</li><li>确认无误后执行转存。</li></ol><p>频道扫描分成“扫描”和“转存”两个手动步骤。这样可以避免关键词设置不合适时，系统自动把不需要的资源也存进网盘。</p><h2 id="频道监控" tabindex="-1">频道监控 <a class="header-anchor" href="#频道监控" aria-label="Permalink to &quot;频道监控&quot;">​</a></h2><p>入口：<code>资源获取 / 频道监控</code></p><p>频道监控用于持续观察某些频道的新消息。它和频道扫描不同：</p><ul><li>频道扫描偏向“扫描历史消息”</li><li>频道监控偏向“持续看新消息”</li></ul><p>频道监控使用监控策略里的搜索来源和转存目标。没有在监控策略里启用的来源，不能直接在频道监控里使用。</p><h2 id="tmdb-看板" tabindex="-1">TMDB 看板 <a class="header-anchor" href="#tmdb-看板" aria-label="Permalink to &quot;TMDB 看板&quot;">​</a></h2><p>入口：<code>资源获取 / TMDB看板</code></p><p>TMDB 看板适合浏览电影和剧集：</p><ul><li>按热度、地区、类型、年份筛选</li><li>搜索具体片名</li><li>查看是否已经加入监控</li><li>手动加入或取消监控</li><li>对某个条目即时搜索资源</li></ul><p>加入监控时，系统使用 TMDB 的准确 ID，不靠片名模糊猜测，能减少同名资源加错的概率。</p><h2 id="榜单订阅" tabindex="-1">榜单订阅 <a class="header-anchor" href="#榜单订阅" aria-label="Permalink to &quot;榜单订阅&quot;">​</a></h2><p>入口：<code>资源获取 / 榜单订阅</code></p><p>榜单订阅适合长期追踪热门内容。当前可按来源查看和订阅榜单，例如猫眼、豆瓣、TMDB。</p><p>启用榜单后，榜单条目会进入监控清单。后续系统会根据监控策略配置的搜索来源继续寻找资源。</p><p>如果只想临时关注某个资源，也可以在榜单卡片或 TMDB 看板里直接加入自定义监控。</p><h2 id="监控清单" tabindex="-1">监控清单 <a class="header-anchor" href="#监控清单" aria-label="Permalink to &quot;监控清单&quot;">​</a></h2><p>入口：<code>资源获取 / 监控清单</code></p><p>监控清单是所有自动跟踪条目的汇总视图。你可以在这里看到：</p><ul><li>条目来自榜单、自定义、豆瓣求片还是缺集补救</li><li>当前是否已入库</li><li>是否已入库但缺集</li><li>最近搜索和转存历史</li><li>手动刷新 TMDB / Emby 状态</li></ul><p>监控清单不是频道配置页，也不是榜单配置页。它更像“当前正在跟踪什么”的总表。</p><h2 id="常见状态" tabindex="-1">常见状态 <a class="header-anchor" href="#常见状态" aria-label="Permalink to &quot;常见状态&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td>未入库</td><td>Emby 里还没有确认找到这个资源。</td></tr><tr><td>完整入库</td><td>Emby 已经确认存在，并且剧集不缺集。</td></tr><tr><td>已入库但缺集</td><td>Emby 里有这个剧集，但按 TMDB 标准季集看仍缺少部分集数。</td></tr><tr><td>转存失败</td><td>本次转存没有成功，需要看日志或处理历史。</td></tr><tr><td>容量不足</td><td>网盘空间不足，清理空间后再手动重试。</td></tr></tbody></table><h2 id="先从哪一个功能开始" tabindex="-1">先从哪一个功能开始 <a class="header-anchor" href="#先从哪一个功能开始" aria-label="Permalink to &quot;先从哪一个功能开始&quot;">​</a></h2><p>如果你刚部署完成，可以先选择自己最常用的一条链路验证配置是否可用：只需要整理频道历史时看频道扫描，需要追踪热门内容时看榜单订阅，需要处理片单需求时看豆瓣求片，需要补齐剧集时看 Emby 缺集扫描。</p>',42)])])}const b=e(r,[["render",d]]);export{u as __pageData,b as default};
